  elanelany: function(a,b){ return Math.hypot(a.x-b.x, a.y-b.y); },
  mifandona: function(a,b){ return a.x < b.x + b.sakany && a.x + a.sakany > b.x && a.y < b.y + b.haavony && a.y + a.haavony > b.y; },
  lerp: function(a,b,t){ return a + (b-a)*t; },
  clamp: function(v,min,max){ return Math.max(min, Math.min(max, v)); },
  rad: function(d){ return d*Math.PI/180; }, deg: function(r){ return r*180/Math.PI; },
  distance: function(x1,y1,x2,y2){ return Math.hypot(x2-x1, y2-y1); },
  angle: function(x1,y1,x2,y2){ return Math.atan2(y2-y1, x2-x1); },
  normalize: function(x,y){ var len=Math.hypot(x,y); return len>0?{x:x/len,y:y/len}:{x:0,y:0}; },
  easeInQuad: function(t){ return t*t; }, easeOutQuad: function(t){ return t*(2-t); },
  easeInOutQuad: function(t){ return t<0.5?2*t*t:-1+(4-2*t)*t; },
  easeInCubic: function(t){ return t*t*t; }, easeOutCubic: function(t){ return (--t)*t*t+1; },
  easeOutBounce: function(t){ if(t<1/2.75) return 7.5625*t*t; else if(t<2/2.75) return 7.5625*(t-=1.5/2.75)*t+0.75; else if(t<2.5/2.75) return 7.5625*(t-=2.25/2.75)*t+0.9375; else return 7.5625*(t-=2.625/2.75)*t+0.984375; },
