R.Spline=function(k,pts){this.kianja=k; this.points=pts||[{x:0,y:0},{x:200,y:100}]; if(k) k.zavatra.push(this);}; R.Spline.prototype.getPoint=function(t){ var pts=this.points; if(pts.length<2) return pts[0]; var p=t*(pts.length-1), i=Math.floor(p), f=p-i; if(i>=pts.length-1) return pts[pts.length-1]; return {x:pts[i].x+(pts[i+1].x-pts[i].x)*f, y:pts[i].y+(pts[i+1].y-pts[i].y)*f}; }; R.Spline.prototype.havaozy=function(){}; R.Spline.prototype.soraty=function(ctx){ ctx.save(); ctx.strokeStyle='#0ff'; ctx.beginPath(); ctx.moveTo(this.points[0].x,this.points[0].y); for(var i=1;i<this.points.length;i++) ctx.lineTo(this.points[i].x,this.points[i].y); ctx.stroke(); ctx.restore(); };
R.UI={Button:function(k,x,y,txt,cb){var b={kianja:k,x:x,y:y,w:120,h:35,text:txt,cb:cb,sakany:120,haavony:35}; b.soraty=function(ctx){ ctx.fillStyle=R.Totozy.x>b.x&&R.Totozy.x<b.x+b.w&&R.Totozy.y>b.y&&R.Totozy.y<b.y+b.h?'#555':'#333'; ctx.fillRect(b.x,b.y,b.w,b.h); ctx.strokeStyle='#FFD700'; ctx.strokeRect(b.x,b.y,b.w,b.h); ctx.fillStyle='#fff'; ctx.textAlign='center'; ctx.fillText(b.text,b.x+b.w/2,b.y+b.h/2+5); }; b.havaozy=function(){ if(R.Totozy.tsindry&&R.Totozy.x>b.x&&R.Totozy.x<b.x+b.w&&R.Totozy.y>b.y&&R.Totozy.y<b.y+b.h){ b.cb&&b.cb(); R.Totozy.tsindry=false; }}; k.zavatra.push(b); return b; }};
R.Liquid=function(k,o){o=o||{}; this.kianja=k; this.x=o.x||0; this.y=o.y||400; this.w=o.sakany||800; this.h=o.haavony||200; this.loko=o.loko||'rgba(0,255,255,0.6)'; this.wave=0; this.particles=[]; for(var i=0;i<80;i++) this.particles.push({x:this.x+Math.random()*this.w,y:this.y+Math.random()*this.h,vx:(Math.random()-0.5)*30,vy:(Math.random()-0.5)*20,r:3+Math.random()*6}); if(k) k.zavatra.push(this);}; R.Liquid.prototype.havaozy=function(dt){ this.wave+=dt*2; var self=this; this.particles.forEach(function(p){ p.x+=p.vx*dt; p.y+=p.vy*dt; if(p.x<self.x) p.x=self.x+self.w; if(p.x>self.x+self.w) p.x=self.x; }); }; R.Liquid.prototype.soraty=function(ctx){ ctx.save(); ctx.fillStyle=this.loko; ctx.beginPath(); ctx.moveTo(this.x,this.y+this.h); for(var x=this.x;x<=this.x+this.w;x+=10) ctx.lineTo(x,this.y+Math.sin(x*0.02+this.wave)*8); ctx.lineTo(this.x+this.w,this.y+this.h); ctx.closePath(); ctx.fill(); this.particles.forEach(function(p){ ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,Math.PI*2); ctx.fill(); }); ctx.restore(); };
R.Polygon=function(k,pts,o){o=o||{}; this.kianja=k; this.points=pts||[{x:0,y:0},{x:100,y:0},{x:100,y:100},{x:0,y:100}]; this.x=o.x||0; this.y=o.y||0; this.loko=o.loko||'#8a2be2'; if(k) k.zavatra.push(this);}; R.Polygon.prototype.havaozy=function(){}; R.Polygon.prototype.soraty=function(ctx){ ctx.save(); ctx.fillStyle=this.loko; ctx.beginPath(); ctx.moveTo(this.points[0].x+this.x,this.points[0].y+this.y); for(var i=1;i<this.points.length;i++) ctx.lineTo(this.points[i].x+this.x,this.points[i].y+this.y); ctx.closePath(); ctx.fill(); ctx.strokeStyle='#0ff'; ctx.stroke(); ctx.restore(); };

