R.ComplexSystem0 = function(k,o){ o=o||{}; this.kianja=k; this.id='cs_0_'+R.Util.uid(); this.x=o.x||0; this.y=o.y||0; this.entities=[]; this.systems=[]; this._time=0; for(var j=0;j<10;j++){ this.entities.push({x:Math.random()*800, y:Math.random()*600, vx:(Math.random()-0.5)*100, vy:(Math.random()-0.5)*100, update:function(dt){ this.x+=this.vx*dt; this.y+=this.vy*dt; }}); } if(k) k.zavatra.push(this); };
R.ComplexSystem0.prototype.havaozy=function(dt){ this._time+=dt; var self=this; this.entities.forEach(function(e){ if(e.update) e.update(dt); }); this.systems.forEach(function(s){ if(s.update) s.update(dt); }); };
R.ComplexSystem0.prototype.soraty=function(ctx){ ctx.save(); ctx.fillStyle='hsl(0,70%,50%)'; this.entities.forEach(function(e){ ctx.fillRect(e.x, e.y, 5,5); }); ctx.restore(); };

